import { num, parseColor } from "./color.mjs";
import {
  camel,
  colors,
  durationMs,
  easings,
  font,
  px,
  scale,
} from "./model.mjs";

const HEADER = `// Houston design tokens — Jetpack Compose constants.
// AUTO-GENERATED by @houston/design-tokens. Do NOT edit by hand.
// Copy or code-generate this file into the Android app module at build time.
//
// Colours are theme pairs: the app resolves them with its own theme state
// (HoustonTheme) rather than the system configuration, matching how the
// web/desktop app toggles [data-theme].

package ai.gethouston.tokens

import androidx.compose.animation.core.CubicBezierEasing
import androidx.compose.animation.core.Easing
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.unit.Dp
import androidx.compose.ui.unit.TextUnit
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp

enum class HoustonTheme { LIGHT, DARK }

data class HoustonThemedColor(val light: Color, val dark: Color) {
    fun resolve(theme: HoustonTheme): Color = if (theme == HoustonTheme.DARK) dark else light
}`;

const f = (value) => `${num(value)}f`;

function color(value) {
  const { r, g, b, a } = parseColor(value);
  return `Color(red = ${f(r)}, green = ${f(g)}, blue = ${f(b)}, alpha = ${f(a)})`;
}

function objectBlock(name, lines) {
  return `object ${name} {\n${lines.map((l) => `    ${l}`).join("\n")}\n}`;
}

export function buildKotlin(light, dark) {
  const lightMap = new Map(colors(light).map((c) => [c.name, c.value]));
  const colorLines = colors(dark).map(
    (c) =>
      `val ${camel(c.name)} = HoustonThemedColor(light = ${color(
        lightMap.get(c.name),
      )}, dark = ${color(c.value)})`,
  );

  const dp = (entries, prefix) =>
    entries.map((e) => `val ${prefix}${camel(e.name)}: Dp = ${px(e.value)}.dp`);

  const parts = [
    HEADER,
    "",
    objectBlock("HoustonColors", colorLines),
    "",
    objectBlock("HoustonSpacing", dp(scale(light, "space"), "space")),
    "",
    objectBlock("HoustonRadius", dp(scale(light, "radius"), "")),
    "",
    objectBlock(
      "HoustonFontSize",
      font(light, "size").map(
        (e) => `val ${camel(e.name)}: TextUnit = ${px(e.value)}.sp`,
      ),
    ),
    "",
    objectBlock(
      "HoustonFontWeight",
      font(light, "weight").map(
        (w) => `val ${w.name} = FontWeight(${w.value})`,
      ),
    ),
    "",
    objectBlock(
      "HoustonFontFamily",
      font(light, "family").map(
        (e) => `const val ${e.name} = ${JSON.stringify(e.value)}`,
      ),
    ),
    "",
    objectBlock(
      "HoustonDuration",
      scale(light, "duration").map(
        (d) => `const val ${d.name}: Long = ${durationMs(d.value)}L`,
      ),
    ),
    "",
    objectBlock(
      "HoustonEasing",
      easings(light).map(
        (e) =>
          `val ${e.name}: Easing = CubicBezierEasing(${e.value.map((n) => `${n}f`).join(", ")})`,
      ),
    ),
    "",
  ];
  return parts.join("\n");
}
